#include<bits/stdc++.h>
using namespace std;
int dp[2005][2005];
int a[2005][2005];
int maxx[2005];
int n, h, d;
int main() {
	cin >> n >> h >> d;
	for (int i = 1; i <= n; i++) {
		int x;
		cin >> x;
		for (int j = 1; j <= x; j++) {
			int y;
			cin >> y;
			a[i][y]++;
		}
	}
	for (int i = 1; i <= h; i++) {
		for (int j = 1; j <= n; j++) {
			dp[j][i] = dp[j][i - 1];
			if (i - d >= 0) {

				dp[j][i] = max(dp[j][i], maxx[i - d]);
				dp[j][i] += a[j][i];
                maxx[i]=max(maxx[i],dp[j][i]);
			}else{
                dp[j][i] += a[j][i];
                 maxx[i]=max(maxx[i],dp[j][i]);
            }

		}
	}
	int ans = 0;
	for (int j = 1; j <= n; ++j) {
		ans = max(ans, dp[j][h]);
	}
	cout << ans;
	return 0;
}
